// n8n Code node (JavaScript)
// Input: [{ collect_file_issues_message: "..." }]
// Output: { tg_messages: [msg1, msg2, ...], tg_message: msg1, summary: {...} }

function escapeHtml(str) {
  return String(str)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");
}

const TG_LIMIT = 4096;

// Режем сообщения под лимит Telegram, стараясь не ломать позиционные блоки
function packChunks(blockHtmlList, headerHtml, limit = TG_LIMIT) {
  const chunks = [];
  let buf = headerHtml;

  for (const b of blockHtmlList) {
    const piece = (buf ? "\n\n" : "") + b;

    if ((buf + piece).length <= limit) {
      buf += piece;
      continue;
    }

    if (buf) chunks.push(buf);

    // Если один блок слишком большой — режем его грубо (редко, но бывает)
    if ((headerHtml + "\n\n" + b).length > limit) {
      const raw = b;
      for (let i = 0; i < raw.length; i += limit) {
        chunks.push(raw.slice(i, i + limit));
      }
      buf = "";
    } else {
      buf = headerHtml + "\n\n" + b;
    }
  }

  if (buf) chunks.push(buf);
  return chunks;
}

/**
 * КЛЮЧЕВОЕ: группируем по строкам.
 * Новый блок начинается ТОЛЬКО когда строка начинается с:
 *   "Позиция ..." или "Позиция №..."
 * Пустые строки внутри блока НЕ разрывают позицию.
 */
function splitIntoPositionBlocks(text) {
  const lines = text.replace(/\r\n/g, "\n").split("\n");
  const blocks = [];
  let cur = [];

  const isPosLine = (line) => /^Позиция(?:\s+№)?\s+/i.test(line.trim());

  for (const line of lines) {
    if (isPosLine(line)) {
      if (cur.length) blocks.push(cur.join("\n").trim());
      cur = [line.trim()];
    } else {
      // сохраняем пустые строки внутри позиции — чтобы читалось
      cur.push(line);
    }
  }
  if (cur.length) blocks.push(cur.join("\n").trim());

  // уберём мусорные пустые блоки
  return blocks.map((b) => b.trim()).filter(Boolean);
}

// --- main ---
const raw = items?.[0]?.json?.collect_file_issues_message;

// Если SQL вернул пусто/NULL — сразу "нет отклонений"
if (!raw || typeof raw !== "string" || !raw.trim()) {
  const msg = "По результатам проверки отклонений от установленных правил и регламентов нет";
  return [
    {
      json: {
        tg_messages: [msg],
        tg_message: msg,
        summary: { positions: 0, issues: 0, errors: 0, warnings: 0 },
      },
    },
  ];
}

const text = raw.trim();

// 1 позиция = 1 text-block
const posBlocks = splitIntoPositionBlocks(text);

let positions = 0;
let issues = 0;
let errors = 0;
let warnings = 0;

const renderedBlocks = [];

for (const b of posBlocks) {
  // Определяем, есть ли нарушение в этом блоке
  const errCount = (b.match(/\[ERROR\]/gi) || []).length;
  const warnCount = (b.match(/\[(WARN|WARNING)\]/gi) || []).length;

  // Slip-блоки без [ERROR] считаем нарушением по ключевой строке
  const hasSlip = /Выявленные\s+несоответствия/i.test(b);

  // Если у тебя в SQL теперь НЕТ [ERROR]/[WARN], а только эмодзи ⛔️/⚠️/ℹ️ —
  // оставим дополнительную проверку по эмодзи, чтобы не потерять нарушения:
  const hasIconError = /⛔️/u.test(b);
  const hasIconWarn = /⚠️/u.test(b);

  const hasAnyIssue =
    errCount > 0 ||
    warnCount > 0 ||
    hasSlip ||
    hasIconError ||
    hasIconWarn;

  if (!hasAnyIssue) continue;

  positions += 1;

  // Счётчики:
  // 1) если есть старые маркеры [ERROR]/[WARN] — используем их
  // 2) иначе считаем по иконкам
  const countByIconError = (b.match(/⛔️/gu) || []).length;
  const countByIconWarn = (b.match(/⚠️/gu) || []).length;

  errors += errCount || countByIconError;
  warnings += warnCount || countByIconWarn;

  // slip отдельно добавляем как нарушение (если он есть и не был учтён как ⛔️)
  issues += (errCount + warnCount) > 0
    ? (errCount + warnCount)
    : (countByIconError + countByIconWarn);

  if (hasSlip && (errCount + warnCount + countByIconError + countByIconWarn) === 0) {
    // на крайний случай, если slip-блок вообще без маркеров и иконок
    errors += 1;
    issues += 1;
  }

  // Один <pre> на одну позицию
  renderedBlocks.push(`<pre>${escapeHtml(b)}</pre>`);
}

// ✅ КЛЮЧЕВОЕ ИЗМЕНЕНИЕ: если после фильтрации нет блоков — не шлём "пустой отчёт"
if (renderedBlocks.length === 0) {
  const msg = "По результатам проверки отклонений от установленных правил и регламентов нет";
  return [
    {
      json: {
        tg_messages: [msg],
        tg_message: msg,
        summary: { positions: 0, issues: 0, errors: 0, warnings: 0 },
      },
    },
  ];
}

const header =
  `<b>📋 Отчёт по проверкам стеклопакетов</b>\n` +
  `Позиции: <b>${positions}</b> · Нарушения: <b>${issues}</b>\n` +
  `Ошибки: <b>${errors}</b> · Предупр.: <b>${warnings}</b>`;

const tg_messages = packChunks(renderedBlocks, header, TG_LIMIT);

if (tg_messages.length > 1) {
  const note = `\n\n<i>Сообщение разбито на ${tg_messages.length} частей из-за ограничения Telegram.</i>`;
  const last = tg_messages[tg_messages.length - 1];
  tg_messages[tg_messages.length - 1] =
    last.length + note.length <= TG_LIMIT ? last + note : last;
}

return [
  {
    json: {
      tg_messages,
      tg_message: tg_messages[0],
      summary: { positions, issues, errors, warnings },
    },
  },
];
